import json
import os
from datetime import datetime, timedelta

class Cache:
    def __init__(self, cache_dir):
        self.cache_dir = cache_dir
        if not os.path.exists(cache_dir):
            os.makedirs(cache_dir)

    def _serialize(self, data):
        return json.dumps(data, separators=(',', ':'))

    def _deserialize(self, serialized_data):
        try:
            return json.loads(serialized_data)
        except json.JSONDecodeError as e:
            print(f"Failed to deserialize cache: {e}")
            return None

    def get(self, key):
        file_path = os.path.join(self.cache_dir, f"{key}.json")
        if os.path.exists(file_path):
            with open(file_path, 'r') as f:
                serialized_data = f.read()
                data = self._deserialize(serialized_data)
                if data is not None and 'expires' in data and datetime.now() < datetime.fromtimestamp(data['expires']):
                    return data
        return None

    def set(self, key, value):
        expires_at = int(datetime.now().timestamp()) + 3600  # cache for 1 hour
        data = {'value': value, 'expires': expires_at}
        serialized_data = self._serialize(data)
        file_path = os.path.join(self.cache_dir, f"{key}.json")
        with open(file_path, 'w') as f:
            f.write(serialized_data)

    def delete(self, key):
        file_path = os.path.join(self.cache_dir, f"{key}.json")
        if os.path.exists(file_path):
            os.remove(file_path)